class LFUCache {
public:
    LFUCache(int capacity) {
        cap = capacity;
        cnt = 0;
    }

    int get(int key) {
        if (!map.count(key)) return -1;
        Node* node = map[key];
        node->freq++;
        if (node->freq == 1) {
            if (freqs.count(1)) freqs[1].erase(node);
            freqs.erase(node->freq);
        }
        freqs[node->freq].insert(node);
        return node->val;
    }

    void put(int key, int value) {
        if (cap == 0) return;
        if (map.count(key)) {
            Node* node = map[key];
            node->val = value;
            node->freq++;
            if (node->freq == 1) {
                if (freqs.count(1)) freqs[1].erase(node);
                freqs.erase(node->freq);
            }
            freqs[node->freq].insert(node);
        } else {
            if (cnt == cap) {
                Node* lru = freqs[1].begin()->second.begin();
                freqs[1].erase(lru);
                if (freqs[1].empty()) freqs.erase(1);
                map.erase(lru->key);
                cnt--;
            }
            Node* node = new Node(key, value, 1);
            freqs[1].insert(node);
            map[key] = node;
            cnt++;
        }
    }
private:
    struct Node {
        int key, val, freq;
        Node(int k, int v, int f) : key(k), val(v), freq(f) {}
    };
    int cap;
    int cnt;
    unordered_map<int, Node*> map;
    unordered_map<int, unordered_set<Node*>> freqs;
};
```

